<html><head><title>Datum formats Quick and Dirty</title><meta http-equiv="Content-Type" content="text/html; charset=iso-8859-1"></head><body><?php$datum = $HTTP_GET_VARS[datum];$datum = stripslashes($datum);$datum = strip_tags($datum);$titel = $HTTP_GET_VARS[titel];$titel = stripslashes($titel);$titel = strip_tags($titel);$description = $HTTP_GET_VARS[description];$description = stripslashes($description);$description = strip_tags($description);$link = $HTTP_GET_VARS[link];$link = stripslashes($link);$link = strip_tags($link);$datetime = strtotime($datum);echo date('l dS of F Y H:i:s A', $datetime)."<hr>voor XML RSS ::: ";echo date('D, d M Y H:i:s A', $datetime)." ::: <hr><p>&lt;item&gt;<br>&lt;title&gt;$titel&lt;/title&gt;&lt;description&gt;$description&lt;/description&gt;&lt;link&gt;$link&lt;/link&gt;&lt;pubDate&gt;<br>&lt;item&gt;</p>";echo date('D, d M Y H:i:s Z', $datetime)."&lt;/pubDate&gt;<p><hr>";echo date('H:i', $datetime)."<hr>";echo date('l dS of F Y h:i:s A', $datetime)."<hr>";?><hr><form action="<?php $_SERVER['PHP_SELF']?>" method="get">  <p>de datum is     <input name="datum" type="text" size="25" value="<?php echo $datum; ?>">  </p>  <p>de titel isis     <input name="titel" type="text" size="75" value="StopOokMetDrinken.nl ::: ">  </p>  <p>de description is     <input name="description" type="text" size="125" value="beschrijving...">  </p>  <p>de link is     <input name="link" type="text" size="125" value="http://www.helpdisk.nl/alcohol/contentnl/login.php">  </p>  <p></p><p>     <input name="submit" type="submit" value="submit">  </p>  </form></body></html>